exercises.solution_code:
#include <iostream>
#include <string>
#include <sstream>
#include <iomanip>

class Formatter
{
public:
    std::string format(double value) const
    {
        std::ostringstream out{};
        out << std::fixed << std::setprecision(1) << value << 'C';
        return out.str();
    }
};

class Thermometer
{
    double m_celsius{};

public:
    Thermometer(double celsius)
        : m_celsius{ celsius }
    {
    }

    void display(const Formatter& fmt) const
    {
        std::cout << "Temperature: " << fmt.format(m_celsius) << '\n';
    }
};

int main()
{
    double temp{};
    std::cin >> temp;

    Formatter fmt{};
    Thermometer t{ temp };
    t.display(fmt);

    return 0;
}

